const getPendingTransfersInputSchema = z.object({
	competitionId: z.string().min(1),
})

/**
 * Get all INITIATED (pending) transfers for a competition.
 * Used by the athletes page to show pending transfer badges.
 */
export const getPendingTransfersForCompetitionFn = createServerFn({
	method: "GET",
})
	.inputValidator((data: unknown) =>
		getPendingTransfersInputSchema.parse(data),
	)
	.handler(async ({ data: input }) => {
		const session = await requireVerifiedEmail()
		const db = getDb()

		updateRequestContext({ userId: session.userId })
		addRequestContextAttribute("competitionId", input.competitionId)

		// Get all INITIATED transfers for purchases in this competition
		const transfers = await db
			.select({
				id: purchaseTransfersTable.id,
				purchaseId: purchaseTransfersTable.purchaseId,
				targetEmail: purchaseTransfersTable.targetEmail,
				transferState: purchaseTransfersTable.transferState,
				expiresAt: purchaseTransfersTable.expiresAt,
			})
			.from(purchaseTransfersTable)
			.innerJoin(
				commercePurchaseTable,
				eq(purchaseTransfersTable.purchaseId, commercePurchaseTable.id),
			)
			.where(
				and(
					eq(commercePurchaseTable.competitionId, input.competitionId),
					eq(
						purchaseTransfersTable.transferState,
						PURCHASE_TRANSFER_STATUS.INITIATED,
					),
				),
			)

		return transfers
	})

import { and, eq, inArray } from "drizzle-orm"
import { getDb } from "@/db"
import {
	competitionEventsTable,
	competitionHeatAssignmentsTable,
	competitionRegistrationAnswersTable,
	competitionRegistrationsTable,
	scoresTable,
	SYSTEM_ROLES_ENUM,
	teamMembershipTable,
	waiverSignaturesTable,
} from "@/db/schema"

interface TransferContext {
	purchaseId: string
	sourceUserId: string
	targetUserId: string
	competitionId: string
	answers?: Array<{ questionId: string; answer: string }>
	waiverSignatures?: Array<{ waiverId: string }>
}

export async function handleCompetitionRegistrationTransfer(
	ctx: TransferContext,
) {
	const db = getDb()

	// 1. Find the registration linked to this purchase
	const registration = await db.query.competitionRegistrationsTable.findFirst({
		where: and(
			eq(competitionRegistrationsTable.commercePurchaseId, ctx.purchaseId),
			eq(competitionRegistrationsTable.status, "active"),
		),
	})

	if (!registration) {
		throw new Error("No active registration found for this purchase")
	}

	// 2. Check target user doesn't already have registration in same division
	//    The unique index is on (eventId, userId, divisionId) regardless of status,
	//    so we must handle both active and removed registrations.
	if (registration.divisionId) {
		const existingReg =
			await db.query.competitionRegistrationsTable.findFirst({
				where: and(
					eq(competitionRegistrationsTable.eventId, registration.eventId),
					eq(competitionRegistrationsTable.userId, ctx.targetUserId),
					eq(
						competitionRegistrationsTable.divisionId,
						registration.divisionId,
					),
				),
			})
		if (existingReg) {
			if (existingReg.status === "active") {
				throw new Error(
					"Target user already has an active registration in this division",
				)
			}
			// Remove the old (non-active) registration so the unique index doesn't block
			await db
				.delete(competitionRegistrationsTable)
				.where(eq(competitionRegistrationsTable.id, existingReg.id))
		}
	}

	// 3. Deactivate source user's team membership in the competition_event team
	if (registration.teamMemberId) {
		await db
			.update(teamMembershipTable)
			.set({ isActive: false, updatedAt: new Date() })
			.where(eq(teamMembershipTable.id, registration.teamMemberId))
	}

	// 4. Create new team membership for target user in the competition_event team
	let newTeamMemberId: string | null = null
	if (registration.teamMemberId) {
		const oldMembership = await db.query.teamMembershipTable.findFirst({
			where: eq(teamMembershipTable.id, registration.teamMemberId),
		})

		if (oldMembership) {
			const inserted = await db
				.insert(teamMembershipTable)
				.values({
					teamId: oldMembership.teamId,
					userId: ctx.targetUserId,
					roleId: oldMembership.roleId,
					isSystemRole: oldMembership.isSystemRole,
					isActive: true,
					joinedAt: new Date(),
				})
				.$returningId()
			newTeamMemberId = inserted[0]?.id ?? null
		}
	}

	// 5. Update registration: userId, captainUserId, teamMemberId
	await db
		.update(competitionRegistrationsTable)
		.set({
			userId: ctx.targetUserId,
			captainUserId: ctx.targetUserId,
			teamMemberId: newTeamMemberId ?? registration.teamMemberId,
			updatedAt: new Date(),
		})
		.where(eq(competitionRegistrationsTable.id, registration.id))

	// 6. Delete heat assignments (athlete needs re-scheduling)
	await db
		.delete(competitionHeatAssignmentsTable)
		.where(
			eq(competitionHeatAssignmentsTable.registrationId, registration.id),
		)

	// 7. Delete old registration answers
	await db
		.delete(competitionRegistrationAnswersTable)
		.where(
			eq(
				competitionRegistrationAnswersTable.registrationId,
				registration.id,
			),
		)

	// 8. Save new registration answers if provided
	if (ctx.answers && ctx.answers.length > 0) {
		for (const answer of ctx.answers) {
			await db.insert(competitionRegistrationAnswersTable).values({
				registrationId: registration.id,
				questionId: answer.questionId,
				userId: ctx.targetUserId,
				answer: answer.answer,
			})
		}
	}

	// 9. Save waiver signatures if provided
	if (ctx.waiverSignatures && ctx.waiverSignatures.length > 0) {
		for (const sig of ctx.waiverSignatures) {
			await db.insert(waiverSignaturesTable).values({
				waiverId: sig.waiverId,
				userId: ctx.targetUserId,
				registrationId: registration.id,
				signedAt: new Date(),
			})
		}
	}

	// 10. For team registrations: swap source→target in athlete team memberships
	if (registration.athleteTeamId) {
		const athleteTeamMemberships = await db
			.select()
			.from(teamMembershipTable)
			.where(
				and(
					eq(teamMembershipTable.teamId, registration.athleteTeamId),
					eq(teamMembershipTable.userId, ctx.sourceUserId),
					eq(teamMembershipTable.isActive, true),
				),
			)

		for (const membership of athleteTeamMemberships) {
			await db
				.update(teamMembershipTable)
				.set({ isActive: false, updatedAt: new Date() })
				.where(eq(teamMembershipTable.id, membership.id))
		}

		await db.insert(teamMembershipTable).values({
			teamId: registration.athleteTeamId,
			userId: ctx.targetUserId,
			roleId: SYSTEM_ROLES_ENUM.CAPTAIN,
			isSystemRole: true,
			isActive: true,
			joinedAt: new Date(),
		})
	}

	// 11. Delete scores for the source user in this competition's events
	const competitionEvents = await db
		.select({ id: competitionEventsTable.id })
		.from(competitionEventsTable)
		.where(eq(competitionEventsTable.competitionId, ctx.competitionId))

	if (competitionEvents.length > 0) {
		const eventIds = competitionEvents.map((e) => e.id)
		await db
			.delete(scoresTable)
			.where(
				and(
					inArray(scoresTable.competitionEventId, eventIds),
					eq(scoresTable.userId, ctx.sourceUserId),
				),
			)
	}
}

import { createId } from "@paralleldrive/cuid2"
import type { InferSelectModel } from "drizzle-orm"
import { relations } from "drizzle-orm"
import {
	index,
	int,
	varchar,
	datetime,
	boolean,
	mysqlTable,
	text,
} from "drizzle-orm/mysql-core"
import { commonColumns } from "./common"
import {
	competitionRegistrationsTable,
	competitionsTable,
} from "./competitions"
import { userTable } from "./users"

// ID generator functions
export const createWaiverId = () => `waiv_${createId()}`
export const createWaiverSignatureId = () => `wsig_${createId()}`

/**
 * Waivers Table
 * Stores waiver documents for competitions. Organizers can create multiple waivers
 * per competition with rich text content (Lexical JSON).
 */
export const waiversTable = mysqlTable(
	"waivers",
	{
		...commonColumns,
		id: varchar({ length: 255 })
			.primaryKey()
			.$defaultFn(() => createWaiverId())
			.notNull(),
		// The competition this waiver belongs to
		competitionId: varchar({ length: 255 }).notNull(),
		// Waiver title (e.g., "Liability Waiver", "Photo Release")
		title: varchar({ length: 255 }).notNull(),
		// Rich text content stored as Lexical JSON
		content: text().notNull(),
		// Whether this waiver is required for registration
		required: boolean().default(true).notNull(),
		// Display order (for showing multiple waivers in sequence)
		position: int().default(0).notNull(),
	},
	(table) => [
		index("waivers_competition_idx").on(table.competitionId),
		index("waivers_position_idx").on(table.competitionId, table.position),
	],
)

/**
 * Waiver Signatures Table
 * Tracks when athletes sign waivers during registration or invite acceptance.
 */
export const waiverSignaturesTable = mysqlTable(
	"waiver_signatures",
	{
		...commonColumns,
		id: varchar({ length: 255 })
			.primaryKey()
			.$defaultFn(() => createWaiverSignatureId())
			.notNull(),
		// The waiver being signed
		waiverId: varchar({ length: 255 }).notNull(),
		// The user who signed the waiver
		userId: varchar({ length: 255 }).notNull(),
		// The registration this signature is associated with (nullable for captains signing during registration creation)
		registrationId: varchar({ length: 255 }),
		// When the waiver was signed
		signedAt: datetime()
			.$defaultFn(() => new Date())
			.notNull(),
		// Optional IP address for audit trail
		ipAddress: varchar({ length: 45 }), // IPv6 max length
	},
	(table) => [
		index("waiver_signatures_waiver_idx").on(table.waiverId),
		index("waiver_signatures_user_idx").on(table.userId),
		index("waiver_signatures_registration_idx").on(table.registrationId),
		// Composite index to quickly check if a user has signed a specific waiver
		index("waiver_signatures_waiver_user_idx").on(table.waiverId, table.userId),
	],
)

// Type exports
export type Waiver = InferSelectModel<typeof waiversTable>
export type WaiverSignature = InferSelectModel<typeof waiverSignaturesTable>

// Relations
export const waiversRelations = relations(waiversTable, ({ one, many }) => ({
	// The competition this waiver belongs to
	competition: one(competitionsTable, {
		fields: [waiversTable.competitionId],
		references: [competitionsTable.id],
	}),
	// All signatures for this waiver
	signatures: many(waiverSignaturesTable),
}))

export const waiverSignaturesRelations = relations(
	waiverSignaturesTable,
	({ one }) => ({
		// The waiver being signed
		waiver: one(waiversTable, {
			fields: [waiverSignaturesTable.waiverId],
			references: [waiversTable.id],
		}),
		// The user who signed
		user: one(userTable, {
			fields: [waiverSignaturesTable.userId],
			references: [userTable.id],
		}),
		// The registration this signature is associated with
		registration: one(competitionRegistrationsTable, {
			fields: [waiverSignaturesTable.registrationId],
			references: [competitionRegistrationsTable.id],
		}),
	}),
)

